from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core
import os

class PrismGetEntityPathNode(BaseNode):
    name = "Prism: Get Entity Path"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("department", "string", widget_type="text", default="")
        self.add_input("task", "string", widget_type="text", default="")
        self.add_output("entity_root", "string")
        self.add_output("dept_path", "string")
        self.add_output("task_path", "string")
        self.add_output("found", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get("entity") or {}
        dept = (inputs.get("department") or "").strip()
        task = (inputs.get("task") or "").strip()
        defaults = {"entity_root": "", "dept_path": "", "task_path": "", "found": False}
        if core is None:
            self.log_error("No PrismCore found.")
            return defaults
        try:
            entity_root = ""
            for method in ("getEntityPath", "getEntityBasePath", "getAssetPath", "getShotPath"):
                fn = getattr(core.entities, method, None)
                if callable(fn):
                    try:
                        entity_root = str(fn(entity) or "")
                        if entity_root:
                            break
                    except Exception:
                        pass
            dept_path = ""
            if dept:
                for method in ("getDepartmentPath", "getStepPath"):
                    fn = getattr(core.entities, method, None)
                    if callable(fn):
                        try:
                            dept_path = str(fn(entity, dept) or "")
                            if dept_path:
                                break
                        except Exception:
                            pass
                if not dept_path and entity_root:
                    dept_path = os.path.join(entity_root, dept)
            task_path = ""
            if task and dept:
                for method in ("getTaskPath", "getWorkPath"):
                    fn = getattr(core.entities, method, None)
                    if callable(fn):
                        try:
                            task_path = str(fn(entity, dept, task) or "")
                            if task_path:
                                break
                        except Exception:
                            pass
                if not task_path and dept_path:
                    task_path = os.path.join(dept_path, task)
            found = bool(entity_root)
            self.log_info(f"entity_root={entity_root!r}  dept={dept_path!r}  task={task_path!r}")
            return {"entity_root": entity_root, "dept_path": dept_path,
                    "task_path": task_path, "found": found}
        except Exception as e:
            self.log_error(f"getEntityPath failed: {e}")
            return defaults

def register_node():
    return PrismGetEntityPathNode
